import ldap
import ldap.filter

def search_user_by_username(ldap_connection, base_dn, username):
    """
    Search for a user in LDAP directory by username with proper escaping
    to prevent LDAP injection attacks.
    
    Args:
        ldap_connection: Active LDAP connection object
        base_dn: Base DN for the search
        username: Username to search for
    
    Returns:
        List of user entries matching the username
    """
    # Escape LDAP special characters in the username
    escaped_username = ldap.filter.escape_filter_chars(username)
    
    # Construct the LDAP filter with fixed structure
    search_filter = f"(&(objectClass=user)(sAMAccountName={escaped_username}))"
    
    try:
        # Perform the search with fixed query structure
        result = ldap_connection.search_s(
            base=base_dn,
            scope=ldap.SCOPE_SUBTREE,
            filterstr=search_filter,
            attrlist=['dn', 'sAMAccountName', 'displayName', 'mail']
        )
        
        # Return only the user entries (ignore result codes)
        return [entry for dn, entry in result if entry]
        
    except ldap.INVALID_CREDENTIALS:
        raise Exception("Invalid LDAP credentials")
    except ldap.NO_SUCH_OBJECT:
        return []
    except ldap.LDAPError as e:
        raise Exception(f"LDAP search failed: {str(e)}")